
import { Component, OnInit } from "@angular/core";
import { FormBuilder, Validators } from "@angular/forms";
import { Router } from "@angular/router";
import { Subject } from "rxjs";
import {
  AddSystemService,
  API_URL,
} from "src/app/shared/services/add-system.service";
import { RuleService } from "src/app/shared/services/rule.service";
import Swal from "sweetalert2";

@Component({
  selector: "npr-conversion",
  templateUrl: "./conversion.component.html",
  styleUrls: ["./conversion.component.scss"],
})
export class ConversionComponent implements OnInit {
  dtTrigger: any = new Subject();
  dtOptions: DataTables.Settings = {};
  ruleMappingListResp: any = [];
  dataResp:any;
 
  conversionForm: any;

  constructor(
    private rulelist: RuleService,
    private router: Router,
    private addSystem: AddSystemService,
    private fb: FormBuilder
  ) {}

  ngOnInit(): void {
    this.conversionForm = this.fb.group({
      FCUBS_HEADER: ["", Validators.required],
      Content_Type: [""],
    });
  }
  process() {
      var xmlhttp = new XMLHttpRequest();
      xmlhttp.open("POST", `${API_URL}/message/readMessage`);
      var xmlDoc;
      var self = this;
      xmlhttp.onreadystatechange = function () {
        if (xmlhttp.readyState == 4 && xmlhttp.status == 200) {
          console.log(xmlhttp);
          self.dataResp =this.response;
         
        
        }
        else if(xmlhttp.readyState == 4 && xmlhttp.status == 400) {
          Swal.fire({text:"Provided Input is incorrect",
        icon:'error'});
          
       }
      };
      if (this.conversionForm.value.Content_Type === "json") {
      xmlhttp.setRequestHeader("Content-Type", "application/json");
      }
      else if(this.conversionForm.value.Content_Type === "xml")
      {
        
        xmlhttp.setRequestHeader("Content-Type", "application/xml");
      }
      
      xmlhttp.send(this.conversionForm.value.FCUBS_HEADER);
    
  }
  onSelect(event){
    this.conversionForm.get('FCUBS_HEADER').setValue('');
    this.dataResp=null;
  }
  ngOnDestroy(): void {
    // Do not forget to unsubscribe the event
    this.dtTrigger.unsubscribe();
  }
}
